import type { ExpressionSpecification } from '@maplibre/maplibre-gl-style-spec';

import { BUBBLE_OUTLINE_STROKE } from '../../../constants.js';

/**
 * It modifies the radius size expression to take the bubble outline stroke size into account
 * @param expression - radius expression
 */
export const addOutlineSize = (
  expression: ExpressionSpecification,
): ExpressionSpecification => ['+', expression, BUBBLE_OUTLINE_STROKE];
